async (params, browser) => {
  // Open messages
  await browser.open('https://x.com/messages')

  // Wait for messages page
  await browser.waitForSelector('[data-testid=\'NewDM_Button\'], a[href=\'/messages/compose\']', 15000)

  // Click new message button
  const open_compose = await browser.evaluate(`const composeBtn = document.querySelector('[data-testid="NewDM_Button"]'); if (composeBtn) composeBtn.click(); else { const altBtn = document.querySelector('a[href="/messages/compose"]'); if (altBtn) altBtn.click(); } return { clicked: true }`)

  await browser.wait(1500)

  // Wait for people search
  await browser.waitForSelector('[data-testid=\'searchPeople\']', 10000)

  // Search for user
  await browser.type('[data-testid=\'searchPeople\']', `${params.username}`, { clear: true })

  // Wait for search results
  await browser.wait(2000)

  // Select user from results
  const select_user = await browser.evaluate(`const results = document.querySelectorAll('[data-testid="TypeaheadUser"]'); if (results.length > 0) { results[0].click(); return { found: true }; } return { found: false, message: 'User not found in search results' }`)

  await browser.wait(1000)

  // Click Next to open conversation
  const click_next = await browser.evaluate(`const nextBtn = document.querySelector('[data-testid="nextButton"]'); if (nextBtn) nextBtn.click(); return { clicked: true }`)

  await browser.wait(1500)

  // Wait for message input
  await browser.waitForSelector('[data-testid=\'dmComposerTextInput\']', 10000)

  // Type message
  const type_message = await browser.evaluate(`const el = document.querySelector('[data-testid="dmComposerTextInput"] [contenteditable="true"], [data-testid="dmComposerTextInput"][contenteditable="true"], [data-testid="dmComposerTextInput"]'); if (!el) throw new Error('DM input not found'); el.focus(); document.execCommand('insertText', false, params.message); el.dispatchEvent(new Event('input', {bubbles: true})); return { typed: true }`)

  await browser.wait(500)

  // Send message
  await browser.click('[data-testid=\'dmComposerSendButton\']')

  await browser.wait(1500)

  const result = await browser.evaluate(`return { success: true, message: 'DM sent successfully' }`)

  return result
}
